import type { Metadata } from "next";
import "./globals.css";

export const metadata: Metadata = {
  title: "Senjuti Bala",
  description:
    "Data scientist working across agent-based modelling, simulation, FAIR data, and visualization.",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" className="h-full">
      <head>
        <link rel="preconnect" href="https://fonts.googleapis.com" />
        <link rel="preconnect" href="https://fonts.gstatic.com" crossOrigin="anonymous" />
        <link
          href="https://fonts.googleapis.com/css2?family=Google+Sans&display=swap"
          rel="stylesheet"
        />
      </head>
      <body className="min-h-full bg-[var(--bg)] text-[var(--ink)] antialiased font-[var(--font-sans)]">
        {children}
      </body>
    </html>
  );
}

@import "tailwindcss";

:root {
  --bg: #FFFFFF;
  --ink: #15140F;
  --muted: #6B6A62;
  --faint: #9B998F;
  --border: rgba(21, 20, 15, 0.14);
  --border-soft: rgba(21, 20, 15, 0.08);
  --accent: #4169E1;
  --accent-soft: #E7EBFB;
  --font-sans: 'Google Sans', sans-serif;
  --font-voice: 'Google Sans', sans-serif;
}

* {
  box-sizing: border-box;
}

::selection {
  background-color: var(--ink);
  color: var(--bg);
}

/* Accordion body height animation, driven from a --xp-h custom property set inline per item */
.xp-body {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.25s ease;
}
.xp-body[data-open="true"] {
  max-height: var(--xp-h, 600px);
}

const navItems = [
  { label: "About", href: "/#about" },
  { label: "Experience", href: "/#experience" },
  { label: "Projects", href: "/#projects" },
  { label: "Contact", href: "/#contact" },
]

export default function Navbar() {
  return (
    <nav className="pt-6">
      <div className="max-w-[700px] mx-auto px-6 flex justify-center items-center flex-wrap gap-2.5 text-[15px] tracking-wide">
        {navItems.map((item, i) => (
          <span key={item.label} className="flex items-center gap-2.5">
            <a
              href={item.href}
              className="text-[var(--accent)] hover:text-[var(--ink)] transition-colors"
            >
              {item.label}
            </a>
            {i < navItems.length - 1 && <span className="text-[var(--faint)]">&middot;</span>}
          </span>
        ))}
      </div>
    </nav>
  )
}

"use client"

import { useState } from "react"

const experiences = [
  {
    company: "RedDot Digital Ltd.",
    role: "Technical Consultant",
    meta: "Dhaka, Bangladesh · Jul 2021 to Aug 2023",
    details: [
      "Owned financial and pricing analysis across 6+ B2B client engagements, including British American Tobacco, Huawei, SMART Axiata, and Netcore.",
      "Built and maintained KPI dashboards in Power BI and revenue tracking, presented directly to C-level decision-makers.",
      "Led the full RFP and tender cycle for 5+ clients across fintech, telecoms, and NGO sectors, with a 100% bid conversion rate on managed accounts.",
      "Reduced manual reporting time through structured data pipelines and Excel automation.",
    ],
    tags: ["Power BI", "Financial Modelling", "Stakeholder Management", "Figma"],
  },
  {
    company: "Distill.io",
    role: "Software Engineer",
    meta: "Bangalore, India · Sep 2020 to Jun 2021",
    details: [
      "Built a point-and-click selector builder and a live preview panel for Scrapex.ai, a no-code web scraping platform.",
      "Built data pipeline interfaces to export scraped data to CSV and JSON.",
    ],
    tags: ["Svelte", "TailwindCSS", "Data Pipelines"],
  },
  {
    company: "SigmaRed Technologies Inc.",
    role: "Developer Intern",
    meta: "Toronto, Canada, Remote · Mar 2020 to Aug 2020",
    details: [
      "Built an ML insights dashboard with interactive charts and model performance tracking.",
      "The MVP directly supported the company's first external funding round.",
    ],
    tags: ["React", "JavaScript", "ML Dashboards"],
  },
  {
    company: "Robi Axiata Ltd.",
    role: "Process Automation Intern (RPA Developer)",
    meta: "Dhaka, Bangladesh · Mar 2019 to Jul 2019",
    details: [
      "Automated HR and finance workflows using Python and Selenium, including automated data entry and scheduled report generation.",
      "Reduced manual processing time across both departments.",
    ],
    tags: ["Python", "Selenium", "RPA"],
  },
]

export default function Experience() {
  const [openIndex, setOpenIndex] = useState(null)

  function toggleItem(index) {
    setOpenIndex(openIndex === index ? null : index)
  }

  return (
    <section id="experience" className="py-11 border-t border-[var(--border-soft)]">
      <h2 className="text-[14.5px] uppercase tracking-[0.12em] text-[var(--muted)] mb-6" style={{ fontFamily: "var(--font-voice)" }}>
        Experience
      </h2>
      <div>
        {experiences.map((exp, index) => (
          <div key={index} className="border-b border-[var(--border-soft)] last:border-b-0">
            <button
              onClick={() => toggleItem(index)}
              className="group w-full text-left py-4 flex justify-between items-start gap-4"
            >
              <div>
                <p className="text-[17px] font-medium text-[var(--accent)] group-hover:text-[var(--ink)] transition-colors">
                  {exp.company}, {exp.role}
                </p>
                <p className="text-[15px] text-[var(--muted)] mt-0.5">{exp.meta}</p>
              </div>
              <span className="text-[18.5px] text-[var(--faint)] shrink-0">
                {openIndex === index ? "−" : "+"}
              </span>
            </button>

            {openIndex === index && (
              <div className="pb-5">
                <ul className="text-[16px] text-[#3a392f] leading-relaxed space-y-1.5 pl-4 list-disc mb-3">
                  {exp.details.map((point, i) => (
                    <li key={i}>{point}</li>
                  ))}
                </ul>
                <div className="flex flex-wrap gap-1.5">
                  {exp.tags.map((tag, i) => (
                    <span
                      key={i}
                      className="text-[13.5px] px-2.5 py-0.5 border border-[var(--border)] rounded-full text-[var(--muted)]"
                    >
                      {tag}
                    </span>
                  ))}
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </section>
  )
}

